import jwt
import json
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: Optional[str] = None, algorithms: list = None) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): The JWT token to decode
        secret (str, optional): Secret key for verification
        algorithms (list, optional): List of allowed algorithms
    
    Returns:
        dict: Decoded token payload and metadata
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512']
    
    try:
        # Decode without verification first to see contents
        payload = jwt.decode(token, options={"verify_signature": False})
        
        # Verify signature if secret provided
        if secret:
            try:
                verified_payload = jwt.decode(token, secret, algorithms=algorithms)
                return {
                    "decoded": payload,
                    "verified": True,
                    "payload": verified_payload
                }
            except jwt.InvalidTokenError as e:
                return {
                    "decoded": payload,
                    "verified": False,
                    "error": str(e)
                }
        else:
            return {
                "decoded": payload,
                "verified": False,
                "warning": "No secret provided, only decoded without verification"
            }
            
    except jwt.ExpiredSignatureError:
        return {
            "error": "Token has expired",
            "decoded": payload if 'payload' in locals() else None
        }
    except jwt.InvalidTokenError as e:
        return {
            "error": f"Invalid token: {str(e)}",
            "decoded": payload if 'payload' in locals() else None
        }

def print_jwt_debug_info(token: str, secret: Optional[str] = None):
    """
    Print formatted debug information about JWT token
    
    Args:
        token (str): The JWT token to analyze
        secret (str, optional): Secret key for verification
    """
    result = decode_jwt(token, secret)
    
    print("=" * 50)
    print("JWT DEBUG INFORMATION")
    print("=" * 50)
    
    if "error" in result:
        print(f"ERROR: {result['error']}")
    
    print(f"DECODED PAYLOAD:")
    if result.get("decoded"):
        for key, value in result["decoded"].items():
            print(f"  {key}: {value}")
    
    if result.get("verified") is True:
        print("\nVERIFICATION: SUCCESS")
        if result.get("payload"):
            print("\nVERIFIED PAYLOAD:")
            for key, value in result["payload"].items():
                print(f"  {key}: {value}")
    elif result.get("verified") is False:
        if "warning" in result:
            print(f"\nWARNING: {result['warning']}")
        if "error" in result:
            print(f"\nVERIFICATION ERROR: {result['error']}")
    
    print("=" * 50)